	P := peakIndex

	// 2. Calculate Increasing Sum (Index 0 to P)
	var sumInc int64 = 0
	for i := 0; i <= P; i++ {
		sumInc += nums[i]
	}

	// 3. Calculate Decreasing Sum (Index P to N-1)
	var sumDec int64 = 0
	for i := P; i < n; i++ {
		sumDec += nums[i]
	}

	// 4. Compare and Return
	if sumInc > sumDec {
		return 0
	} else if sumDec > sumInc {
		return 1
	} else {
		return -1
	}
}
